        ctx,
        RBTDRM_COLOPHON_DEPOT_LIST,
        &[],
        &[],
        dir,
        "list-pre",
    ) {
        Ok(r) => r,
        Err(e) => return rbtdre_Verdict::Fail(format!("depot list (pre-levy): {}", e)),
    };
    if list_pre.exit_code != 0 {
        return rbtdre_Verdict::Fail(format!(
            "depot list (pre-levy) exit {}\n{}",
            list_pre.exit_code, list_pre.stderr
        ));
    }

    let tincture = match rbtdrp_burs_tincture() {
        Ok(t) => t,
        Err(e) => return rbtdre_Verdict::Fail(format!("read BURS_TINCTURE: {}", e)),
    };
    let family_stem = rbtdrp_family_stem_arc(&tincture);
    let moniker = match rbtdrp_pick_next_moniker(&list_pre, &root, &family_stem) {
        Ok(m) => m,
